const scaleCompactU32Bytes = (value, label) => {
  if (!Number.isInteger(value) || value < 0 || value > 0xffff_ffff) {
    throw new RangeError(`${label} length must fit u32`);
  }
  if (value < 1 << 6) {
    return new Uint8Array([value << 2]);
  }
  if (value < 1 << 14) {
    const encoded = value * 4 + 0b01;
    return new Uint8Array([encoded & 0xff, Math.floor(encoded / 0x100) & 0xff]);
  }
  if (value < 1 << 30) {
    const encoded = value * 4 + 0b10;
    return new Uint8Array([
      encoded & 0xff,
      Math.floor(encoded / 0x100) & 0xff,
      Math.floor(encoded / 0x1_0000) & 0xff,
      Math.floor(encoded / 0x100_0000) & 0xff,
    ]);
  }
  return concatBytes(
    new Uint8Array([0b11]),
    writeU32Le(new Uint8Array(), value),
  );
};

const scaleVecBytes = (value, label) =>
  concatBytes(scaleCompactU32Bytes(value.length, label), value);

const encodeSubstrateSccpRuntimeCall = (argumentBytes) => {
  let out = scaleVecBytes(
    textEncoder.encode(SCCP_SUBSTRATE_SUBMIT_MESSAGE_PROOF_ENTRYPOINT_V1),
    "verifierEntrypoint",
  );
  for (const [index, value] of argumentBytes.entries()) {
    out = concatBytes(out, scaleVecBytes(value, `arguments[${index}]`));
  }
  return out;
};

const writeU8 = (target, value) => {
  const out = new Uint8Array(1);
  out[0] = value;
  return concatBytes(target, out);
};

const writeU16Le = (target, value) => {
  const out = new Uint8Array(2);
  new DataView(out.buffer).setUint16(0, Number(value), true);
  return concatBytes(target, out);
};

const writeU32Le = (target, value) => {
  const out = new Uint8Array(4);
  new DataView(out.buffer).setUint32(0, Number(value), true);
  return concatBytes(target, out);
};

const writeI32Le = (target, value) => {
  const out = new Uint8Array(4);
  new DataView(out.buffer).setInt32(0, Number(value), true);
  return concatBytes(target, out);
};

const writeU64Le = (target, value) => {
  const out = new Uint8Array(8);
  const view = new DataView(out.buffer);
  view.setBigUint64(0, normalizeUnsignedBigInt(value, "u64"), true);
  return concatBytes(target, out);
};

const readU32LeAt = (bytes, offset, label) => {
  if (offset + 4 > bytes.length) {
    throw new TypeError(`${label} is too short`);
  }
  return new DataView(bytes.buffer, bytes.byteOffset + offset, 4).getUint32(
    0,
    true,
  );
};

const readU16LeAt = (bytes, offset, label) => {
  if (offset + 2 > bytes.length) {
    throw new TypeError(`${label} is too short`);
  }
  return new DataView(bytes.buffer, bytes.byteOffset + offset, 2).getUint16(
    0,
    true,
  );
};

const readU8At = (bytes, offset, label) => {
  if (offset + 1 > bytes.length) {
    throw new TypeError(`${label} is too short`);
  }
  return bytes[offset];
};

const readU64LeAt = (bytes, offset, label) => {
  if (offset + 8 > bytes.length) {
    throw new TypeError(`${label} is too short`);
  }
  return new DataView(bytes.buffer, bytes.byteOffset + offset, 8).getBigUint64(
    0,
    true,
  );
};

const writeU16Be = (target, value) => {
  const out = new Uint8Array(2);
  new DataView(out.buffer).setUint16(0, Number(value), false);
  return concatBytes(target, out);
};

const writeU32Be = (target, value) => {
  const out = new Uint8Array(4);
  new DataView(out.buffer).setUint32(0, Number(value), false);
  return concatBytes(target, out);
};

const writeU64Be = (target, value) => {
  const out = new Uint8Array(8);
  new DataView(out.buffer).setBigUint64(
    0,
    normalizeUnsignedBigInt(value, "u64"),
    false,
  );
  return concatBytes(target, out);
};

const abiWordU32 = (value, label = "u32") => {
  const out = new Uint8Array(32);
  new DataView(out.buffer).setUint32(
    28,
    normalizeSccpDomainId(value, label),
    false,
  );
  return out;
};

const abiWordAddress20 = (value, label = "address") => {
  if (!(value instanceof Uint8Array) || value.length !== 20) {
    throw new TypeError(`${label} must be 20 bytes`);
  }
  const out = new Uint8Array(32);
  out.set(value, 12);
  return out;
};

const abiWordBytes21 = (value, label = "bytes21") => {
  if (!(value instanceof Uint8Array) || value.length !== 21) {
    throw new TypeError(`${label} must be 21 bytes`);
  }
  const out = new Uint8Array(32);
  out.set(value, 11);
  return out;
};

const abiWordU64 = (value, label = "u64") => {
  const out = new Uint8Array(32);
  new DataView(out.buffer).setBigUint64(
    24,
    normalizeUnsignedBigInt(value, label),
    false,
  );
  return out;
};

const abiWordU256 = (value, label = "u256") => {
  let numeric = normalizeUnsignedBigInt(value, label);
  if (numeric >= 1n << 256n) {
    throw new RangeError(`${label} must fit u256`);
  }
  const out = new Uint8Array(32);
  for (let index = 31; index >= 0; index -= 1) {
    out[index] = Number(numeric & 0xffn);
    numeric >>= 8n;
  }
  return out;
};

const abiPadBytes = (bytes) => {
  const paddedLength = Math.ceil(bytes.length / 32) * 32;
  const out = new Uint8Array(paddedLength);
  out.set(bytes);
  return out;
};

const abiDynamicBytes = (bytes, label = "bytes") =>
  concatBytes(abiWordU256(bytes.length, `${label}.length`), abiPadBytes(bytes));

const writeU128Le = (target, value) => {
  const numeric = normalizeUnsignedBigInt(value, "u128");
  const out = new Uint8Array(16);
  let working = numeric;
  for (let index = 0; index < 16; index += 1) {
    out[index] = Number(working & 0xffn);
    working >>= 8n;
  }
  return concatBytes(target, out);
};

const readU128LeAt = (bytes, offset, label) => {
  if (offset + 16 > bytes.length) {
    throw new TypeError(`${label} is too short`);
  }
  let value = 0n;
  for (let index = 15; index >= 0; index -= 1) {
    value = (value << 8n) | BigInt(bytes[offset + index]);
  }
  return value;
};

const writeBytes = (target, value) => {
  const bytes = toBytes(value, "bytes");
  return concatBytes(writeU32Le(target, bytes.length), bytes);
};

const toMaybeEmptyBytes = (value, label) => {
  if (typeof value === "string" && value.trim().toLowerCase() === "0x") {
    return new Uint8Array();
  }
  return toBytes(value, label);
};

const writeProtobufVarint = (target, value, label = "protobufVarint") => {
  let numeric = normalizeUnsignedBigInt(value, label);
  const bytes = [];
  do {
    let byte = Number(numeric & 0x7fn);
    numeric >>= 7n;
    if (numeric !== 0n) byte |= 0x80;
    bytes.push(byte);
  } while (numeric !== 0n);
  return concatBytes(target, Uint8Array.from(bytes));
};

const writeProtobufU64 = (target, fieldNumber, value) =>
  writeProtobufVarint(
    writeProtobufVarint(target, BigInt((fieldNumber << 3) | 0), "protobufKey"),
    value,
    `protobufField${fieldNumber}`,
  );

const writeProtobufBytes = (target, fieldNumber, value) => {
  const bytes = toBytes(value, `protobufField${fieldNumber}`);
  return concatBytes(
    writeProtobufVarint(
      writeProtobufVarint(
        target,
        BigInt((fieldNumber << 3) | 2),
        "protobufKey",
      ),
      BigInt(bytes.length),
      "protobufLength",
    ),
    bytes,
  );
};

const protobufVarintLen = (value) => {
  let working = value;
  let length = 1;
  while (working >= 0x80n) {
    length += 1;
    working >>= 7n;
  }
  return length;
};

const readCanonicalProtobufVarint = (bytes, cursor, label) => {
  const start = cursor.offset;
  let value = 0n;
  let shift = 0n;
  for (let index = 0; index < 10; index += 1) {
    if (cursor.offset >= bytes.length) {
      throw new TypeError(`${label} contains truncated protobuf varint`);
    }
    const byte = bytes[cursor.offset];
    cursor.offset += 1;
    const chunk = BigInt(byte & 0x7f);
    if (index === 9 && chunk > 1n) {
      throw new RangeError(`${label} protobuf varint must fit u64`);
    }
    value |= chunk << shift;
    if ((byte & 0x80) === 0) {
      if (cursor.offset - start !== protobufVarintLen(value)) {
        throw new TypeError(`${label} protobuf varint must be canonical`);
      }
      return value;
    }
    shift += 7n;
  }
  throw new RangeError(`${label} protobuf varint must fit u64`);
};

const writeString = (target, value, label) => {
  if (typeof value !== "string" || value.trim() === "") {
    throw new TypeError(`${label} must be a non-empty string`);
  }
  return writeBytes(target, textEncoder.encode(value.trim()));
};

const isCanonicalDecimalText = (value) =>
  value === "0" || /^[1-9][0-9]*$/.test(value);

const normalizeUnsignedBigInt = (value, label) => {
  if (typeof value === "bigint") {
    if (value < 0n) throw new RangeError(`${label} must not be negative`);
    return value;
  }
  if (typeof value === "number") {
    if (!Number.isInteger(value) || value < 0 || !Number.isSafeInteger(value)) {
      throw new RangeError(`${label} must be a non-negative safe integer`);
    }
    return BigInt(value);
  }
  if (typeof value === "string") {
    if (!isCanonicalDecimalText(value)) {
      throw new TypeError(`${label} must be an unsigned integer`);
    }
    return BigInt(value);
  }
  throw new TypeError(`${label} must be an unsigned integer`);
};

const normalizeUnsignedBigIntMax = (value, label, max, typeLabel) => {
  const numeric = normalizeUnsignedBigInt(value, label);
  if (numeric > max) {
    throw new RangeError(`${label} must fit ${typeLabel}`);
  }
  return numeric;
};

const normalizeV1Version = (value, label, ErrorCtor = RangeError) => {
  if (value === null) {
    throw new TypeError(`${label} must be 1`);
  }
  const version = normalizeUnsignedBigInt(
    value === undefined ? 1 : value,
    label,
  );
  if (version !== 1n) {
    throw new ErrorCtor(`${label} must be 1`);
  }
  return 1;
};

const normalizeSignedI32 = (value, label) => {
  if (typeof value === "bigint") {
    if (value < -2147483648n || value > 2147483647n) {
      throw new RangeError(`${label} must fit i32`);
    }
    return Number(value);
  }
  if (typeof value === "number") {
    if (!Number.isInteger(value) || value < -2147483648 || value > 2147483647) {
      throw new RangeError(`${label} must fit i32`);
    }
    return value;
  }
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (!/^-?\d+$/.test(trimmed)) {
      throw new TypeError(`${label} must be a signed integer`);
    }
    return normalizeSignedI32(BigInt(trimmed), label);
  }
  throw new TypeError(`${label} must be a signed integer`);
};

const prefixedKeccak = (prefix, payload) =>
  keccak_256(concatBytes(textEncoder.encode(prefix), payload));

const prefixedBlake2b = (prefix, payload) =>
  blake2b(concatBytes(textEncoder.encode(prefix), payload), { dkLen: 32 });

const normalizeHex32 = (value, label) =>
  bytesToHex(hexToBytes(value, label, 32));

const SCCP_OPTIONAL_FIELD_MISSING = Symbol("sccpOptionalFieldMissing");

const optionalResultField = (value, ...names) => {
  for (const name of names) {
    if (Object.prototype.hasOwnProperty.call(value, name)) return value[name];
  }
  return SCCP_OPTIONAL_FIELD_MISSING;
};

const strictOptionalResultField = (value, label, ...names) => {
  const present = names.filter((name) =>
    Object.prototype.hasOwnProperty.call(value, name),
  );
  if (present.length > 1) {
    throw new TypeError(`${label} must not use multiple aliases`);
  }
  return present.length === 0 ? SCCP_OPTIONAL_FIELD_MISSING : value[present[0]];
};

const strictResultField = (value, label, ...names) => {
  const selected = strictOptionalResultField(value, label, ...names);
  return selected === SCCP_OPTIONAL_FIELD_MISSING ? undefined : selected;
};

const strictOptionalConstructorOption = (value, label, ...names) => {
  const selected = strictOptionalResultField(value, label, ...names);
  return selected === SCCP_OPTIONAL_FIELD_MISSING || selected == null
    ? null
    : selected;
};

const normalizeOptionalV1Version = (
  input,
  label,
  ErrorCtor = RangeError,
  ...names
) => {
  const versionInput = optionalResultField(input, ...names);
  if (versionInput === SCCP_OPTIONAL_FIELD_MISSING) {
    return 1;
  }
  if (versionInput === null || versionInput === undefined) {
    throw new TypeError(`${label} must be 1`);
  }
  return normalizeV1Version(versionInput, label, ErrorCtor);
};

const requireV1Version = (value, label, ErrorCtor = TypeError) => {
  if (value === null || value === undefined) {
    throw new TypeError(`${label} must be 1`);
  }
  return normalizeV1Version(value, label, ErrorCtor);
};

const requireOptionalResultHashMatches = (actual, expected, label) => {
  if (actual === undefined || actual === null) return;
  if (
    normalizeHexInput(actual, label, 32) !==
    normalizeHexInput(expected, label, 32)
  ) {
    throw new TypeError(`${label} must match request`);
  }
};

const requireSuppliedResultHashMatches = (actual, expected, label) => {
  if (
    normalizeHexInput(actual, label, 32) !==
    normalizeHexInput(expected, label, 32)
  ) {
    throw new TypeError(`${label} must match request`);
  }
};

const requireOptionalResultBackendMatches = (actual, expected) => {
  if (actual === undefined || actual === null) return;
  if (actual !== expected) {
    throw new TypeError("backend must match request");
  }
};

const requireSuppliedResultBackendMatches = (actual, expected) => {
  if (actual !== expected) {
    throw new TypeError("backend must match request");
  }
};

const nonZeroHex32Bytes = (value, label) => {
  const bytes = hexToBytes(value, label, 32);
  if (bytes.every((byte) => byte === 0)) {
    throw new TypeError(`${label} must not be zero`);
  }
  return bytes;
};

const isNonZeroTronAddress = (address) =>
  address.length === 21 &&
  address[0] === 0x41 &&
  address.subarray(1).some((byte) => byte !== 0);

const normalizeNonZeroHex32 = (value, label) =>
  bytesToHex(nonZeroHex32Bytes(value, label));

const normalizeCanonicalNativeEvmProverBundleHex32 = (value, label) => {
  const normalized = normalizeNonZeroHex32(value, label);
  if (value !== normalized) {
    throw new TypeError(
      `${label} must be canonical lowercase 0x-prefixed 32-byte hex`,
    );
  }
  return normalized;
};

const bytesToBigInt = (bytes) => BigInt(`0x${bytesToHex(bytes, false)}`);

const bigIntToBytes32 = (value) => {
  const hex = value.toString(16).padStart(64, "0");
  return hexToBytes(hex, "fieldElement", 32);
};

const groth16Bn254SignalWord = (label, value) => {
  const labelHash = keccak_256(textEncoder.encode(label));
  const digest = keccak_256(concatBytes(labelHash, value));
  return bigIntToBytes32(
    bytesToBigInt(digest) % SCCP_GROTH16_BN254_SCALAR_FIELD_MODULUS,
  );
};

const normalizeNonEmptyString = (value, label) => {
  if (typeof value !== "string" || value.trim() === "") {
    throw new TypeError(`${label} must be a non-empty string`);
  }
  return value.trim();
};

const decodeSolanaBase58 = (value, label) => {
  const text = normalizeNonEmptyString(value, label);
  let numeric = 0n;
  for (const char of text) {
    const digit = SOLANA_BASE58_INDEX.get(char);
    if (digit === undefined) {
      throw new TypeError(`${label} must be canonical base58`);
    }
    numeric = numeric * 58n + digit;
  }
  let leadingZeros = 0;
  while (leadingZeros < text.length && text[leadingZeros] === "1") {
    leadingZeros += 1;
  }
  let payload = new Uint8Array();
  if (numeric !== 0n) {
    const hex = numeric.toString(16);
    payload = hexToBytes(hex.length % 2 === 0 ? hex : `0${hex}`, label);
  }
  return concatBytes(new Uint8Array(leadingZeros), payload);
};

const decodeSolanaBase58Fixed = (value, label, byteLength) => {
  const bytes = decodeSolanaBase58(value, label);
  if (bytes.length !== byteLength) {
    throw new TypeError(`${label} must decode to ${byteLength} bytes`);
  }
  if (bytes.every((byte) => byte === 0)) {
    throw new TypeError(`${label} must not decode to zero`);
  }
  return bytes;
};

const decodeTronBase58CheckPayload = (value, label) => {
  if (typeof value !== "string" || value === "") {
    throw new TypeError(`${label} must be a non-empty string`);
  }
  if (value.trim() !== value) {
    throw new TypeError(`${label} must be a canonical base58check address`);
  }
  const text = value;
  const decoded = decodeSolanaBase58(text, label);
  if (decoded.length < 5) {
    throw new TypeError(`${label} must be a base58check address`);
  }
  const payload = decoded.slice(0, -4);
  const checksum = decoded.slice(-4);
  const expected = sha256(sha256(payload)).slice(0, 4);
  if (!bytesEqual(checksum, expected)) {
    throw new TypeError(`${label} must have a valid base58check checksum`);
  }
  if (payload.length !== 21 || payload[0] !== 0x41) {
    throw new TypeError(`${label} must use TRON 0x41 prefix`);
  }
  if (!payload.slice(1).some((byte) => byte !== 0)) {
    throw new TypeError(`${label} must not be zero`);
  }
  return payload;
};

const normalizeTronAddressPayload = (value, label) => {
  if (typeof value === "string") {
    const text = value.trim();
    if (text !== value) {
      throw new TypeError(`${label} must be canonical`);
    }
    const hexText = text.replace(/^0x/i, "");
    if (/^[0-9a-fA-F]+$/u.test(hexText)) {
      if (hexText.length === 40) {
        const payload = concatBytes(
          Uint8Array.of(0x41),
          hexToBytes(hexText, label, 20),
        );
        if (!isNonZeroTronAddress(payload)) {
          throw new TypeError(`${label} must be a non-zero TRON address`);
        }
        return payload;
      }
      if (hexText.length === 42 && hexText.slice(0, 2).toLowerCase() === "41") {
        const payload = hexToBytes(hexText, label, 21);
        if (!isNonZeroTronAddress(payload)) {
          throw new TypeError(`${label} must be a non-zero TRON address`);
        }
        return payload;
      }
    }
    return decodeTronBase58CheckPayload(value, label);
  }
  const bytes = toBytes(value, label);
  const payload =
    bytes.length === 20 ? concatBytes(Uint8Array.of(0x41), bytes) : bytes;
  if (!isNonZeroTronAddress(payload)) {
    throw new TypeError(`${label} must be a non-zero TRON address`);
  }
  return payload;
};

const tronAddressAbiWord = (value, label) =>
  abiWordAddress20(normalizeTronAddressPayload(value, label).slice(1), label);

const normalizeSolanaBase58FixedString = (value, label, byteLength) => {
  const text = normalizeNonEmptyString(value, label);
  decodeSolanaBase58Fixed(text, label, byteLength);
  return text;
};

const normalizeSolanaHash32Bytes = (value, label) => {
  if (typeof value === "string") {
    const trimmed = value.trim();
    const hex = trimmed.replace(/^0x/i, "");
    if (hex.length === 64 && !/[^0-9a-fA-F]/.test(hex)) {
      return nonZeroHex32Bytes(trimmed, label);
    }
    return decodeSolanaBase58Fixed(trimmed, label, 32);
  }
  const bytes = toBytes(value, label);
  if (bytes.length !== 32) {
    throw new TypeError(`${label} must be 32 bytes`);
  }
  if (bytes.every((byte) => byte === 0)) {
    throw new TypeError(`${label} must not be zero`);
  }
  return bytes;
};

const bytesToBase64 = (bytes) => {
  const bufferCtor = globalThis.Buffer;
  if (typeof bufferCtor !== "undefined") {
    return bufferCtor.from(bytes).toString("base64");
  }
  let binary = "";
  for (const byte of bytes) binary += String.fromCharCode(byte);
  return btoa(binary);
};

const base64ToBytesStrict = (value, label) => {
  const text = normalizeNonEmptyString(value, label);
  if (text !== value || /\s/.test(text) || text.length % 4 !== 0) {
    throw new TypeError(`${label} must be canonical base64`);
  }
  const bufferCtor = globalThis.Buffer;
  let bytes;
  if (typeof bufferCtor !== "undefined") {
    bytes = new Uint8Array(bufferCtor.from(text, "base64"));
  } else {
    const binary = atob(text);
    bytes = new Uint8Array(binary.length);
    for (let index = 0; index < binary.length; index += 1) {
      bytes[index] = binary.charCodeAt(index);
    }
  }
  if (bytesToBase64(bytes) !== text) {
    throw new TypeError(`${label} must be canonical base64`);
  }
  return bytes;
};

const normalizeTokenMessagePayload = (payload) => {
  if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
    throw new TypeError("token message payload must be an object");
  }
  if (
    typeof payload.kind === "string" &&
    payload.value &&
    typeof payload.value === "object"
  ) {
    return {
      kind: payload.kind,
      value: payload.value,
    };
  }
  if ("TokenAdd" in payload) {
    return { kind: "TokenAdd", value: payload.TokenAdd };
  }
  if ("TokenPause" in payload) {
    return { kind: "TokenPause", value: payload.TokenPause };
  }
  if ("TokenResume" in payload) {
    return { kind: "TokenResume", value: payload.TokenResume };
  }
  throw new TypeError(
    "token message payload must be TokenAdd, TokenPause, or TokenResume",
  );
};

const normalizeGovernanceMessagePayload = (payload) => {
  if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
    throw new TypeError("governance payload must be an object");
  }
  if ("Add" in payload) {
    return { kind: "TokenAdd", value: payload.Add };
  }
  if ("Pause" in payload) {
    return { kind: "TokenPause", value: payload.Pause };
  }
  if ("Resume" in payload) {
    return { kind: "TokenResume", value: payload.Resume };
  }
  return normalizeTokenMessagePayload(payload);
};

const messageKindCode = (kind) => {
  switch (kind) {
    case "Burn":
      return 0;
    case "TokenAdd":
      return 1;
    case "TokenPause":
      return 2;
    case "TokenResume":
      return 3;
    case "AssetRegister":
      return 4;
    case "RouteActivate":
      return 5;
    case "Transfer":
      return 6;
    default:
      throw new TypeError(`unsupported SCCP message kind: ${kind}`);
  }
};

const SCCP_SUPPORTED_DOMAINS = [
  SCCP_DOMAIN_SORA,
  SCCP_DOMAIN_ETH,
  SCCP_DOMAIN_BSC,
  SCCP_DOMAIN_SOL,
  SCCP_DOMAIN_TON,
  SCCP_DOMAIN_TRON,
  SCCP_DOMAIN_SORA_KUSAMA,
  SCCP_DOMAIN_SORA_POLKADOT,
  SCCP_DOMAIN_SORA2,
];

export const isSupportedSccpDomain = (domainId) => {
  try {
    return SCCP_SUPPORTED_DOMAINS.includes(
      normalizeSccpDomainId(domainId, "domainId"),
    );
  } catch (_error) {
    return false;
  }
};

const normalizeSccpCodecId = (value, label) =>
  Number(normalizeUnsignedBigIntMax(value, label, 255n, "u8"));

const sccpCounterpartyAccountCodec = (domain) => {
  switch (domain) {
    case SCCP_DOMAIN_SORA:
    case SCCP_DOMAIN_SORA_KUSAMA:
    case SCCP_DOMAIN_SORA_POLKADOT:
    case SCCP_DOMAIN_SORA2:
      return SCCP_CODEC_TEXT_UTF8;
    case SCCP_DOMAIN_ETH:
    case SCCP_DOMAIN_BSC:
      return SCCP_CODEC_EVM_HEX;
    case SCCP_DOMAIN_SOL:
      return SCCP_CODEC_SOLANA_BASE58;
    case SCCP_DOMAIN_TON:
      return SCCP_CODEC_TON_RAW;
    case SCCP_DOMAIN_TRON:
      return SCCP_CODEC_TRON_BASE58CHECK;
    default:
      return null;
  }
};

const normalizeCanonicalTextBytes = (value, label) => {
  const text = normalizeNonEmptyString(value, label);
  if (text !== value) {
    throw new TypeError(`${label} must be canonical text`);
  }
  return textEncoder.encode(text);
};

const normalizeCanonicalTairaAccountId = (value, label) => {
  const text = normalizeNonEmptyString(value, label);
  if (text !== value) {
    throw new TypeError(`${label} must be canonical text`);
  }
  try {
    const address = AccountAddress.fromAccountId(
      text,
      SCCP_TAIRA_NETWORK_PREFIX_V1,
    );
    if (address.toI105(SCCP_TAIRA_NETWORK_PREFIX_V1) !== text) {
      throw new TypeError(
        `${label} must use canonical TAIRA I105 account id form`,
      );
    }
    return text;
  } catch (error) {
    if (error instanceof TypeError) {
      throw error;
    }
    throw new TypeError(`${label} must be a canonical TAIRA I105 account id`);
  }
};

const validateCanonicalEvmHexAddress = (text, label) => {
  if (!/^0x[0-9a-fA-F]{40}$/u.test(text)) {
    throw new TypeError(`${label} must be a 0x-prefixed 20-byte EVM address`);
  }
  const payload = text.slice(2);
  const lowercasePayload = payload.toLowerCase();
  const checksum = keccak_256(textEncoder.encode(lowercasePayload));
  for (let index = 0; index < payload.length; index += 1) {
    const char = payload[index];
    if (/[0-9]/u.test(char)) continue;
    const checksumByte = checksum[Math.floor(index / 2)];
    const checksumNibble =
      index % 2 === 0 ? checksumByte >> 4 : checksumByte & 0x0f;
    const shouldBeUppercase = checksumNibble >= 8;
    if (
      shouldBeUppercase
        ? char !== char.toUpperCase()
        : char !== char.toLowerCase()
    ) {
      throw new TypeError(`${label} must be a canonical EIP-55 EVM address`);
    }
  }
};

const canonicalEip55HexAddress = (value, label) => {
  const bytes = nonZeroHexBytes(value, label, 20);
  const lowercasePayload = bytesToHex(bytes, false);
  const checksum = keccak_256(textEncoder.encode(lowercasePayload));
  let output = "0x";
  for (let index = 0; index < lowercasePayload.length; index += 1) {
    const char = lowercasePayload[index];
    if (/[0-9]/u.test(char)) {
      output += char;
      continue;
    }
    const checksumByte = checksum[Math.floor(index / 2)];
    const checksumNibble =
      index % 2 === 0 ? checksumByte >> 4 : checksumByte & 0x0f;
    output += checksumNibble >= 8 ? char.toUpperCase() : char;
  }
  return output;
};

const decodeSolanaBase58FixedAllowZero = (value, label, byteLength) => {
  const text = normalizeNonEmptyString(value, label);
  if (text.length < 32 || text.length > 44) {
    throw new TypeError(
      `${label} must be a canonical 32-byte Solana base58 address`,
    );
  }
  const bytes = decodeSolanaBase58(text, label);
  if (bytes.length !== byteLength) {
    throw new TypeError(`${label} must decode to ${byteLength} bytes`);
  }
  return bytes;
};

const validateCanonicalTonRawAddress = (text, label) => {
  const [workchain, accountHex, extra] = text.split(":");
  if (extra !== undefined || accountHex === undefined) {
    throw new TypeError(`${label} must be workchain:account_hex`);
  }
  if (
    workchain === "" ||
    workchain.startsWith("+") ||
    (workchain.startsWith("-") &&
      (workchain.length === 1 || workchain.slice(1) === "0")) ||
    /^-?0[0-9]/u.test(workchain)
  ) {
    throw new TypeError(`${label} workchain must be canonical i32`);
  }
  normalizeSignedI32(workchain, `${label} workchain`);
  if (accountHex.length !== 64 || /[^0-9a-f]/u.test(accountHex)) {
    throw new TypeError(`${label} account must be lowercase 32-byte hex`);
  }
};

const normalizeSccpCodecValueBytes = (value, codec, label) => {
  switch (codec) {
    case SCCP_CODEC_TEXT_UTF8:
      return normalizeCanonicalTextBytes(value, label);
    case SCCP_CODEC_EVM_HEX: {
      const text = normalizeNonEmptyString(value, label);
      if (text !== value) {
        throw new TypeError(`${label} must be canonical text`);
      }
      validateCanonicalEvmHexAddress(text, label);
      return textEncoder.encode(text);
    }
    case SCCP_CODEC_SOLANA_BASE58: {
      const text = normalizeNonEmptyString(value, label);
      if (text !== value) {
        throw new TypeError(`${label} must be canonical text`);
      }
      decodeSolanaBase58FixedAllowZero(text, label, 32);
      return textEncoder.encode(text);
    }
    case SCCP_CODEC_TON_RAW: {
      const text = normalizeNonEmptyString(value, label);
      if (text !== value) {
        throw new TypeError(`${label} must be canonical text`);
      }
      validateCanonicalTonRawAddress(text, label);
      return textEncoder.encode(text);
    }
    case SCCP_CODEC_TRON_BASE58CHECK: {
      const text = normalizeNonEmptyString(value, label);
      if (text !== value) {
        throw new TypeError(
          `${label} must be a canonical TRON base58check address`,
        );
      }
      decodeTronBase58CheckPayload(text, label);
      return textEncoder.encode(text);
    }
    case SCCP_CODEC_SORA_ASSET_ID: {
      const bytes = toBytes(value, label);
      if (bytes.length !== 32) {
        throw new TypeError(`${label} must be 32 bytes`);
      }
      return bytes;
    }
    default:
      throw new RangeError(`${label} codec is unsupported`);
  }
};

const readCanonicalSccpVec = (payload, offset, label) => {
  const length = readU32LeAt(payload, offset, `${label}.length`);
  const valueOffset = offset + 4;
  if (valueOffset + length > payload.length) {
    throw new TypeError(`${label} is too short`);
  }
  return {
    bytes: payload.subarray(valueOffset, valueOffset + length),
    nextOffset: valueOffset + length,
  };
};

const decodeCanonicalUtf8Bytes = (bytes, label) => {
  let text;
  try {
    text = textDecoder.decode(bytes);
  } catch (_error) {
    throw new TypeError(`${label} must be valid UTF-8`);
  }
  if (!bytesEqual(textEncoder.encode(text), bytes)) {
    throw new TypeError(`${label} must be canonical UTF-8`);
  }
  return text;
};

const parseTairaXorCanonicalTransferPayloadBytes = (value) => {
  const payload = toBytes(value, "canonicalPayloadBytes");
  if (payload.length === 0) {
    throw new TypeError("canonicalPayloadBytes must not be empty");
  }
  let offset = 0;
  const version = readU8At(payload, offset, "canonicalPayloadBytes.version");
  if (version !== 1) {
    throw new TypeError("canonicalPayloadBytes.version must be 1");
  }
  offset += 1;

  const sourceDomain = readU32LeAt(
    payload,
    offset,
    "canonicalPayloadBytes.source_domain",
  );
  if (sourceDomain !== SCCP_DOMAIN_SORA) {
    throw new TypeError("canonicalPayloadBytes.source_domain must be SORA");
  }
  offset += 4;

  const destDomain = readU32LeAt(
    payload,
    offset,
    "canonicalPayloadBytes.dest_domain",
  );
  if (destDomain !== SCCP_DOMAIN_TRON) {
    throw new TypeError("canonicalPayloadBytes.dest_domain must be TRON");
  }
  offset += 4;

  const nonce = readU64LeAt(payload, offset, "canonicalPayloadBytes.nonce");
  offset += 8;

  const assetHomeDomain = readU32LeAt(
    payload,
    offset,
    "canonicalPayloadBytes.asset_home_domain",
  );
  if (assetHomeDomain !== SCCP_DOMAIN_SORA) {
    throw new TypeError("canonicalPayloadBytes.asset_home_domain must be SORA");
  }
  offset += 4;

  const assetIdCodec = readU8At(
    payload,
    offset,
    "canonicalPayloadBytes.asset_id_codec",
  );
  if (assetIdCodec !== SCCP_CODEC_TEXT_UTF8) {
    throw new TypeError(
      "canonicalPayloadBytes.asset_id_codec must be TEXT_UTF8",
    );
  }
  offset += 1;
  let valueRange = readCanonicalSccpVec(
    payload,
    offset,
    "canonicalPayloadBytes.asset_id",
  );
  offset = valueRange.nextOffset;
  const assetId = decodeCanonicalUtf8Bytes(
    valueRange.bytes,
    "canonicalPayloadBytes.asset_id",
  );
  if (assetId !== SCCP_TAIRA_XOR_ASSET_KEY_V1) {
    throw new TypeError("canonicalPayloadBytes.asset_id must be xor");
  }

  const amount = readU128LeAt(payload, offset, "canonicalPayloadBytes.amount");
  if (amount === 0n) {
    throw new RangeError(
      "canonicalPayloadBytes.amount must be greater than zero",
    );
  }
  offset += 16;

  const senderCodec = readU8At(
    payload,
    offset,
    "canonicalPayloadBytes.sender_codec",
  );
  if (senderCodec !== SCCP_CODEC_TEXT_UTF8) {
    throw new TypeError("canonicalPayloadBytes.sender_codec must be TEXT_UTF8");
  }
  offset += 1;
  valueRange = readCanonicalSccpVec(
    payload,
    offset,
    "canonicalPayloadBytes.sender",
  );
  offset = valueRange.nextOffset;
  const sender = normalizeCanonicalTairaAccountId(
    decodeCanonicalUtf8Bytes(valueRange.bytes, "canonicalPayloadBytes.sender"),
    "canonicalPayloadBytes.sender",
  );

  const recipientCodec = readU8At(
    payload,
    offset,
    "canonicalPayloadBytes.recipient_codec",
  );
  if (recipientCodec !== SCCP_CODEC_TRON_BASE58CHECK) {
    throw new TypeError(
      "canonicalPayloadBytes.recipient_codec must be TRON_BASE58CHECK",
    );
  }
  offset += 1;
  valueRange = readCanonicalSccpVec(
    payload,
    offset,
    "canonicalPayloadBytes.recipient",
  );
  offset = valueRange.nextOffset;
  const recipient = decodeCanonicalUtf8Bytes(
    valueRange.bytes,
    "canonicalPayloadBytes.recipient",
  );
  decodeTronBase58CheckPayload(recipient, "canonicalPayloadBytes.recipient");

  const routeIdCodec = readU8At(
    payload,
    offset,
    "canonicalPayloadBytes.route_id_codec",
  );
  if (routeIdCodec !== SCCP_CODEC_TEXT_UTF8) {
    throw new TypeError(
      "canonicalPayloadBytes.route_id_codec must be TEXT_UTF8",
    );
  }
  offset += 1;
  valueRange = readCanonicalSccpVec(
    payload,
    offset,
    "canonicalPayloadBytes.route_id",
  );
  offset = valueRange.nextOffset;
  const routeId = decodeCanonicalUtf8Bytes(
    valueRange.bytes,
    "canonicalPayloadBytes.route_id",
  );
  if (routeId !== SCCP_TAIRA_TRON_XOR_ROUTE_ID_V1) {
    throw new TypeError(
      "canonicalPayloadBytes.route_id must be taira_tron_xor",
    );
  }
  if (offset !== payload.length) {
    throw new TypeError(
      "canonicalPayloadBytes must not contain trailing bytes",
    );
  }

  return Object.freeze({
    version,
    source_domain: sourceDomain,
    dest_domain: destDomain,
    nonce,
    asset_home_domain: assetHomeDomain,
    asset_id_codec: assetIdCodec,
    asset_id: assetId,
    amount,
    sender_codec: senderCodec,
    sender,
    recipient_codec: recipientCodec,
    recipient,
    route_id_codec: routeIdCodec,
    route_id: routeId,
  });
};

const requireOptionalTairaXorPayloadInputMatches = (input, parsedPayload) => {
  const routeId = strictOptionalResultField(
    input,
    "routeId",
    "routeId",
    "route_id",
  );
  if (
    routeId !== SCCP_OPTIONAL_FIELD_MISSING &&
    normalizeTairaXorRouteIdInput({ routeId }) !== parsedPayload.route_id
  ) {
    throw new TypeError("routeId must match canonicalPayloadBytes");
  }

  const assetKey = strictOptionalResultField(
    input,
    "assetKey",
    "assetKey",
    "asset_key",
    "assetId",
    "asset_id",
  );
  if (
    assetKey !== SCCP_OPTIONAL_FIELD_MISSING &&
    normalizeTairaXorAssetKeyInput({ assetKey }) !== parsedPayload.asset_id
  ) {
    throw new TypeError("assetKey must match canonicalPayloadBytes");
  }

  const sender = strictOptionalResultField(
    input,
    "sender",
    "sender",
    "tairaSender",
    "taira_sender",
    "tairaAccountId",
    "taira_account_id",
  );
  if (
    sender !== SCCP_OPTIONAL_FIELD_MISSING &&
    normalizeCanonicalTairaAccountId(sender, "sender") !== parsedPayload.sender
  ) {
    throw new TypeError("sender must match canonicalPayloadBytes");
  }

  const recipient = strictOptionalResultField(
    input,
    "recipientAddress",
    "recipientAddress",
    "recipient_address",
    "recipient",
  );
  if (recipient !== SCCP_OPTIONAL_FIELD_MISSING) {
    const normalizedRecipient = normalizeNonEmptyString(
      recipient,
      "recipientAddress",
    );
    if (normalizedRecipient !== recipient) {
      throw new TypeError("recipientAddress must be canonical text");
    }
    decodeTronBase58CheckPayload(normalizedRecipient, "recipientAddress");
    if (normalizedRecipient !== parsedPayload.recipient) {
      throw new TypeError("recipientAddress must match canonicalPayloadBytes");
    }
  }

  const amount = strictOptionalResultField(input, "amount", "amount");
  if (
    amount !== SCCP_OPTIONAL_FIELD_MISSING &&
    normalizeUnsignedBigIntMax(amount, "amount", SCCP_U128_MAX, "u128") !==
      parsedPayload.amount
  ) {
    throw new TypeError("amount must match canonicalPayloadBytes");
  }

  const nonce = strictOptionalResultField(input, "nonce", "nonce");
  if (
    nonce !== SCCP_OPTIONAL_FIELD_MISSING &&
    normalizeUnsignedBigIntMax(nonce, "nonce", SCCP_U64_MAX, "u64") !==
      parsedPayload.nonce
  ) {
    throw new TypeError("nonce must match canonicalPayloadBytes");
  }
};

const normalizeTairaXorRouteIdInput = (input, label = "routeId") => {
  const selected = strictOptionalResultField(
    input,
    label,
    "routeId",
    "route_id",
  );
  const routeId =
    selected === SCCP_OPTIONAL_FIELD_MISSING
      ? SCCP_TAIRA_TRON_XOR_ROUTE_ID_V1
      : normalizeNonEmptyString(selected, label);
  if (routeId !== SCCP_TAIRA_TRON_XOR_ROUTE_ID_V1) {
    throw new TypeError(`${label} must be ${SCCP_TAIRA_TRON_XOR_ROUTE_ID_V1}`);
  }
  return routeId;
};

