const sha256Hex32 = (bytes, label) => bytesToHex(sha256(toBytes(bytes, label)));

const requiredNativeEvmProverArtifactBytes = (input, label, ...aliases) =>
  toBytes(requiredNativeEvmProverBundleField(input, label, ...aliases), label);

const optionalNativeEvmProverArtifactBytes = (input, label, ...aliases) => {
  const value = strictOptionalResultField(input, label, ...aliases);
  return value === SCCP_OPTIONAL_FIELD_MISSING
    ? undefined
    : toBytes(value, label);
};

const nativeEvmProverArtifactMarker = (...codes) => [
  String.fromCharCode(...codes),
  Uint8Array.from(codes),
];

const SCCP_NATIVE_EVM_PROVER_FORBIDDEN_ARTIFACT_MARKERS = [
  nativeEvmProverArtifactMarker(
    0x77,
    0x65,
    0x62,
    0x61,
    0x73,
    0x73,
    0x65,
    0x6d,
    0x62,
    0x6c,
    0x79,
  ),
  nativeEvmProverArtifactMarker(0x77, 0x61, 0x73, 0x6d),
  nativeEvmProverArtifactMarker(0x73, 0x6e, 0x61, 0x72, 0x6b, 0x6a, 0x73),
  nativeEvmProverArtifactMarker(
    0x72,
    0x65,
    0x6d,
    0x6f,
    0x74,
    0x65,
    0x70,
    0x72,
    0x6f,
    0x76,
    0x65,
    0x72,
  ),
  nativeEvmProverArtifactMarker(
    0x72,
    0x65,
    0x6d,
    0x6f,
    0x74,
    0x65,
    0x20,
    0x70,
    0x72,
    0x6f,
    0x76,
    0x65,
    0x72,
  ),
  nativeEvmProverArtifactMarker(
    0x72,
    0x65,
    0x6d,
    0x6f,
    0x74,
    0x65,
    0x5f,
    0x70,
    0x72,
    0x6f,
    0x76,
    0x65,
    0x72,
  ),
  nativeEvmProverArtifactMarker(
    0x70,
    0x72,
    0x6f,
    0x76,
    0x65,
    0x72,
    0x5f,
    0x75,
    0x72,
    0x6c,
  ),
  nativeEvmProverArtifactMarker(
    0x70,
    0x72,
    0x6f,
    0x76,
    0x65,
    0x72,
    0x2d,
    0x75,
    0x72,
    0x6c,
  ),
  nativeEvmProverArtifactMarker(
    0x70,
    0x72,
    0x6f,
    0x76,
    0x65,
    0x72,
    0x65,
    0x6e,
    0x64,
    0x70,
    0x6f,
    0x69,
    0x6e,
    0x74,
  ),
  nativeEvmProverArtifactMarker(
    0x70,
    0x72,
    0x6f,
    0x76,
    0x65,
    0x72,
    0x20,
    0x65,
    0x6e,
    0x64,
    0x70,
    0x6f,
    0x69,
    0x6e,
    0x74,
  ),
];
const SCCP_NATIVE_EVM_PROVER_MIN_ARTIFACT_BYTES_V1 = 256;

const nativeEvmProverLowerAsciiByte = (byte) =>
  byte >= 0x41 && byte <= 0x5a ? byte + 0x20 : byte;

function nativeEvmProverArtifactContainsMarker(bytes, marker) {
  for (let offset = 0; offset <= bytes.length - marker.length; offset += 1) {
    let matched = true;
    for (let index = 0; index < marker.length; index += 1) {
      if (
        nativeEvmProverLowerAsciiByte(bytes[offset + index]) !== marker[index]
      ) {
        matched = false;
        break;
      }
    }
    if (matched) {
      return true;
    }
  }
  return false;
}

function assertNativeEvmProverArtifactHasNoForbiddenDependencyMarkers(
  bytes,
  label,
) {
  for (const [
    marker,
    markerBytes,
  ] of SCCP_NATIVE_EVM_PROVER_FORBIDDEN_ARTIFACT_MARKERS) {
    if (nativeEvmProverArtifactContainsMarker(bytes, markerBytes)) {
      throw new TypeError(
        `${label} contains forbidden prover dependency marker: ${marker}`,
      );
    }
  }
}

function assertNativeEvmProverArtifactHasProductionSize(bytes, label) {
  if (bytes.length < SCCP_NATIVE_EVM_PROVER_MIN_ARTIFACT_BYTES_V1) {
    throw new TypeError(
      `${label} must be at least ${SCCP_NATIVE_EVM_PROVER_MIN_ARTIFACT_BYTES_V1} bytes`,
    );
  }
}

const verifyNativeEvmProverArtifacts = (
  input,
  options = {},
  profile,
) => {
  requireNativeEvmProverBundleObject(
    input,
    `${profile.displayName} native EVM prover artifacts`,
  );
  const manifestInput = strictOptionalResultField(
    input,
    "nativeProverBundle",
    "nativeProverBundle",
    "native_prover_bundle",
    "proverBundle",
    "prover_bundle",
    "manifest",
  );
  if (manifestInput === SCCP_OPTIONAL_FIELD_MISSING) {
    throw new TypeError("nativeProverBundle is required");
  }
  if (typeof manifestInput === "string") {
    rejectDuplicateJsonObjectKeys(manifestInput, "nativeProverBundle");
  }
  const nativeProverBundle = validateNativeEvmProverBundle(
    typeof manifestInput === "string" ? JSON.parse(manifestInput) : manifestInput,
    {
      ...options,
      profile,
    },
  );
  const proofArtifactBytes = requiredNativeEvmProverArtifactBytes(
    input,
    "proofArtifactBytes",
    "proofArtifactBytes",
    "proof_artifact_bytes",
    "proverArtifactBytes",
    "prover_artifact_bytes",
    "circuitArtifactBytes",
    "circuit_artifact_bytes",
  );
  const provingKeyBytes = requiredNativeEvmProverArtifactBytes(
    input,
    "provingKeyBytes",
    "provingKeyBytes",
    "proving_key_bytes",
  );
  const verifierKeyBytes = requiredNativeEvmProverArtifactBytes(
    input,
    "verifierKeyBytes",
    "verifierKeyBytes",
    "verifier_key_bytes",
  );
  const crossSdkFixtureParityBytes = requiredNativeEvmProverArtifactBytes(
    input,
    "crossSdkFixtureParityBytes",
    "crossSdkFixtureParityBytes",
    "cross_sdk_fixture_parity_bytes",
    "parityFixtureBytes",
    "parity_fixture_bytes",
  );
  const nativeProverSelfTestBytes = requiredNativeEvmProverArtifactBytes(
    input,
    "nativeProverSelfTestBytes",
    "nativeProverSelfTestBytes",
    "native_prover_self_test_bytes",
    "selfTestBytes",
    "self_test_bytes",
  );
  const proofArtifactHash = sha256Hex32(
    proofArtifactBytes,
    "proofArtifactBytes",
  );
  const provingKeyHash = sha256Hex32(provingKeyBytes, "provingKeyBytes");
  const verifierKeyHash = sha256Hex32(verifierKeyBytes, "verifierKeyBytes");
  const crossSdkFixtureParityHash = sha256Hex32(
    crossSdkFixtureParityBytes,
    "crossSdkFixtureParityBytes",
  );
  const nativeProverSelfTestHash = sha256Hex32(
    nativeProverSelfTestBytes,
    "nativeProverSelfTestBytes",
  );
  if (proofArtifactHash !== nativeProverBundle.proofArtifactHash) {
    throw new TypeError(
      "proofArtifactBytes sha256 must match nativeProverBundle.proofArtifactHash",
    );
  }
  if (provingKeyHash !== nativeProverBundle.provingKeyHash) {
    throw new TypeError(
      "provingKeyBytes sha256 must match nativeProverBundle.provingKeyHash",
    );
  }
  if (verifierKeyHash !== nativeProverBundle.verifierKeyHash) {
    throw new TypeError(
      "verifierKeyBytes sha256 must match nativeProverBundle.verifierKeyHash",
    );
  }
  if (
    crossSdkFixtureParityHash !==
    nativeProverBundle.auditHashes.cross_sdk_fixture_parity
  ) {
    throw new TypeError(
      "crossSdkFixtureParityBytes sha256 must match nativeProverBundle.auditHashes.cross_sdk_fixture_parity",
    );
  }
  if (
    nativeProverSelfTestHash !==
    nativeProverBundle.auditHashes.native_prover_self_test
  ) {
    throw new TypeError(
      "nativeProverSelfTestBytes sha256 must match nativeProverBundle.auditHashes.native_prover_self_test",
    );
  }
  assertNativeEvmProverArtifactHasProductionSize(
    proofArtifactBytes,
    "proofArtifactBytes",
  );
  assertNativeEvmProverArtifactHasProductionSize(
    provingKeyBytes,
    "provingKeyBytes",
  );
  assertNativeEvmProverArtifactHasProductionSize(
    verifierKeyBytes,
    "verifierKeyBytes",
  );
  assertNativeEvmProverArtifactHasNoForbiddenDependencyMarkers(
    proofArtifactBytes,
    "proofArtifactBytes",
  );
  assertNativeEvmProverArtifactHasNoForbiddenDependencyMarkers(
    provingKeyBytes,
    "provingKeyBytes",
  );
  assertNativeEvmProverArtifactHasNoForbiddenDependencyMarkers(
    verifierKeyBytes,
    "verifierKeyBytes",
  );
  assertNativeEvmProverArtifactHasNoForbiddenDependencyMarkers(
    crossSdkFixtureParityBytes,
    "crossSdkFixtureParityBytes",
  );
  assertNativeEvmProverArtifactHasNoForbiddenDependencyMarkers(
    nativeProverSelfTestBytes,
    "nativeProverSelfTestBytes",
  );
  const parityJson = textDecoder.decode(crossSdkFixtureParityBytes);
  rejectDuplicateJsonObjectKeys(parityJson, "nativeProverParityFixture");
  const crossSdkFixtureParity = validateNativeEvmProverParityFixture(
    JSON.parse(parityJson),
    nativeProverBundle,
    profile,
  );
  const selfTestJson = textDecoder.decode(nativeProverSelfTestBytes);
  rejectDuplicateJsonObjectKeys(selfTestJson, "nativeProverSelfTestFixture");
  const nativeProverSelfTest = validateNativeEvmProverSelfTestFixture(
    JSON.parse(selfTestJson),
    nativeProverBundle,
    profile,
  );
  const sdk = strictOptionalResultField(input, "sdk", "sdk");
  const implementationBytes = optionalNativeEvmProverArtifactBytes(
    input,
    "implementationBytes",
    "implementationBytes",
    "implementation_bytes",
    "nativeImplementationBytes",
    "native_implementation_bytes",
  );
  if (typeof sdk !== "string" || sdk.length === 0) {
    throw new TypeError(
      "sdk must be a non-empty string for nativeProverBundle implementation binding",
    );
  }
  if (implementationBytes === undefined) {
    throw new TypeError(
      "implementationBytes are required for nativeProverBundle implementation binding",
    );
  }
  const artifact = nativeProverBundle.nativeSdkArtifacts.find(
    (row) => row.sdk === sdk,
  );
  if (artifact === undefined) {
    throw new TypeError(
      `nativeProverBundle has no artifact row for sdk: ${sdk}`,
    );
  }
  const implementationHash = sha256Hex32(
    implementationBytes,
    "implementationBytes",
  );
  if (implementationHash !== artifact.implementationHash) {
    throw new TypeError(
      "implementationBytes sha256 must match nativeProverBundle implementationHash",
    );
  }
  assertNativeEvmProverArtifactHasProductionSize(
    implementationBytes,
    "implementationBytes",
  );
  assertNativeEvmProverArtifactHasNoForbiddenDependencyMarkers(
    implementationBytes,
    "implementationBytes",
  );
  const implementation = artifact.implementation;
  return immutableProverCallbackValue({
    hashAlgorithm: SCCP_NATIVE_EVM_PROVER_ARTIFACT_HASH_ALGORITHM_V1,
    nativeProverBundle,
    proofArtifactHash,
    provingKeyHash,
    verifierKeyHash,
    crossSdkFixtureParityHash,
    crossSdkFixtureParity,
    nativeProverSelfTestHash,
    nativeProverSelfTest,
    sdk,
    implementation,
    implementationHash,
  });
};

