const hasEthereumMainnetNativeEvmProverArtifactBytes = (input) =>
  [
    "proofArtifactBytes",
    "proof_artifact_bytes",
    "proverArtifactBytes",
    "prover_artifact_bytes",
    "circuitArtifactBytes",
    "circuit_artifact_bytes",
    "provingKeyBytes",
    "proving_key_bytes",
    "verifierKeyBytes",
    "verifier_key_bytes",
    "crossSdkFixtureParityBytes",
    "cross_sdk_fixture_parity_bytes",
    "parityFixtureBytes",
    "parity_fixture_bytes",
    "nativeProverSelfTestBytes",
    "native_prover_self_test_bytes",
    "selfTestBytes",
    "self_test_bytes",
    "implementationBytes",
    "implementation_bytes",
    "nativeImplementationBytes",
    "native_implementation_bytes",
  ].some((name) => Object.prototype.hasOwnProperty.call(input, name));

const SCCP_ETH_NATIVE_PROVER_BUNDLE_FACTORY_ONLY_KEYS = new Set([
  "nativeProverBundle",
  "native_prover_bundle",
  "proverBundle",
  "prover_bundle",
  "manifest",
  "nativeProverArtifacts",
  "native_prover_artifacts",
  "verifiedNativeProverArtifacts",
  "verified_native_prover_artifacts",
  "artifactResolver",
  "artifact_resolver",
  "resolveArtifact",
  "resolve_artifact",
  "resolveArtifactBytes",
  "resolve_artifact_bytes",
  "sdk",
]);

const ethereumMainnetSccpConstructorOptionsFromBundleFactoryInput = (
  input,
  nativeProverArtifacts,
) => {
  const options = {};
  for (const [key, value] of Object.entries(input)) {
    if (!SCCP_ETH_NATIVE_PROVER_BUNDLE_FACTORY_ONLY_KEYS.has(key)) {
      options[key] = value;
    }
  }
  options.nativeProverBundle = nativeProverArtifacts.nativeProverBundle;
  options.nativeProverArtifacts = nativeProverArtifacts;
  return options;
};

const normalizeVerifiedNativeEvmProverArtifacts = (
  input,
  options = {},
  profile = nativeEvmProverBundleProfiles.ethereumMainnet,
) => {
  requireNativeEvmProverBundleObject(
    input,
    `${profile.displayName} verified native EVM prover artifacts`,
  );
  const hashAlgorithm = strictResultField(
    input,
    "nativeProverArtifacts.hashAlgorithm",
    "hashAlgorithm",
    "hash_algorithm",
  );
  if (hashAlgorithm !== SCCP_NATIVE_EVM_PROVER_ARTIFACT_HASH_ALGORITHM_V1) {
    throw new TypeError("nativeProverArtifacts hashAlgorithm is not supported");
  }
  const nativeProverBundle = validateNativeEvmProverBundle(
    strictResultField(
      input,
      "nativeProverArtifacts.nativeProverBundle",
      "nativeProverBundle",
      "native_prover_bundle",
      "proverBundle",
      "prover_bundle",
    ),
    {
      ...options,
      profile,
    },
  );
  const proofArtifactHash = normalizeNonZeroHex32(
    strictResultField(
      input,
      "nativeProverArtifacts.proofArtifactHash",
      "proofArtifactHash",
      "proof_artifact_hash",
      "proverArtifactHash",
      "prover_artifact_hash",
    ),
    "nativeProverArtifacts.proofArtifactHash",
  );
  const provingKeyHash = normalizeNonZeroHex32(
    strictResultField(
      input,
      "nativeProverArtifacts.provingKeyHash",
      "provingKeyHash",
      "proving_key_hash",
    ),
    "nativeProverArtifacts.provingKeyHash",
  );
  const verifierKeyHash = normalizeNonZeroHex32(
    strictResultField(
      input,
      "nativeProverArtifacts.verifierKeyHash",
      "verifierKeyHash",
      "verifier_key_hash",
    ),
    "nativeProverArtifacts.verifierKeyHash",
  );
  if (proofArtifactHash !== nativeProverBundle.proofArtifactHash) {
    throw new TypeError(
      "nativeProverArtifacts proofArtifactHash must match nativeProverBundle",
    );
  }
  if (provingKeyHash !== nativeProverBundle.provingKeyHash) {
    throw new TypeError(
      "nativeProverArtifacts provingKeyHash must match nativeProverBundle",
    );
  }
  if (verifierKeyHash !== nativeProverBundle.verifierKeyHash) {
    throw new TypeError(
      "nativeProverArtifacts verifierKeyHash must match nativeProverBundle",
    );
  }
  const crossSdkFixtureParityHash = normalizeNonZeroHex32(
    strictResultField(
      input,
      "nativeProverArtifacts.crossSdkFixtureParityHash",
      "crossSdkFixtureParityHash",
      "cross_sdk_fixture_parity_hash",
      "parityFixtureHash",
      "parity_fixture_hash",
    ),
    "nativeProverArtifacts.crossSdkFixtureParityHash",
  );
  if (
    crossSdkFixtureParityHash !==
    nativeProverBundle.auditHashes.cross_sdk_fixture_parity
  ) {
    throw new TypeError(
      "nativeProverArtifacts crossSdkFixtureParityHash must match nativeProverBundle.auditHashes.cross_sdk_fixture_parity",
    );
  }
  const nativeProverSelfTestHash = normalizeNonZeroHex32(
    strictResultField(
      input,
      "nativeProverArtifacts.nativeProverSelfTestHash",
      "nativeProverSelfTestHash",
      "native_prover_self_test_hash",
      "selfTestHash",
      "self_test_hash",
    ),
    "nativeProverArtifacts.nativeProverSelfTestHash",
  );
  if (
    nativeProverSelfTestHash !==
    nativeProverBundle.auditHashes.native_prover_self_test
  ) {
    throw new TypeError(
      "nativeProverArtifacts nativeProverSelfTestHash must match nativeProverBundle.auditHashes.native_prover_self_test",
    );
  }
  const crossSdkFixtureParity = validateNativeEvmProverParityFixture(
    strictResultField(
      input,
      "nativeProverArtifacts.crossSdkFixtureParity",
      "crossSdkFixtureParity",
      "cross_sdk_fixture_parity",
      "parityFixture",
      "parity_fixture",
    ),
    nativeProverBundle,
    profile,
  );
  const nativeProverSelfTest = validateNativeEvmProverSelfTestFixture(
    strictResultField(
      input,
      "nativeProverArtifacts.nativeProverSelfTest",
      "nativeProverSelfTest",
      "native_prover_self_test",
      "selfTest",
      "self_test",
    ),
    nativeProverBundle,
    profile,
  );
  const sdk = strictOptionalResultField(
    input,
    "nativeProverArtifacts.sdk",
    "sdk",
  );
  const implementation = strictOptionalResultField(
    input,
    "nativeProverArtifacts.implementation",
    "implementation",
  );
  const implementationHashInput = strictOptionalResultField(
    input,
    "nativeProverArtifacts.implementationHash",
    "implementationHash",
    "implementation_hash",
  );
  const implementationHash =
    implementationHashInput === SCCP_OPTIONAL_FIELD_MISSING
      ? undefined
      : normalizeNonZeroHex32(
          implementationHashInput,
          "nativeProverArtifacts.implementationHash",
        );
  if (typeof sdk !== "string" || sdk.length === 0) {
    throw new TypeError("nativeProverArtifacts.sdk must be a non-empty string");
  }
  if (implementation === SCCP_OPTIONAL_FIELD_MISSING) {
    throw new TypeError("nativeProverArtifacts.implementation is required");
  }
  if (implementationHash === undefined) {
    throw new TypeError("nativeProverArtifacts.implementationHash is required");
  }
  const artifact = nativeProverBundle.nativeSdkArtifacts.find(
    (row) => row.sdk === sdk,
  );
  if (artifact === undefined) {
    throw new TypeError(
      `nativeProverBundle has no artifact row for sdk: ${sdk}`,
    );
  }
  if (implementation !== artifact.implementation) {
    throw new TypeError(
      "nativeProverArtifacts implementation must match nativeProverBundle",
    );
  }
  if (implementationHash !== artifact.implementationHash) {
    throw new TypeError(
      "nativeProverArtifacts implementationHash must match nativeProverBundle",
    );
  }
  return immutableProverCallbackValue({
    hashAlgorithm,
    nativeProverBundle,
    proofArtifactHash,
    provingKeyHash,
    verifierKeyHash,
    crossSdkFixtureParityHash,
    crossSdkFixtureParity,
    nativeProverSelfTestHash,
    nativeProverSelfTest,
    sdk,
    implementation,
    implementationHash,
  });
};

